import type { I18nOptions } from '@meli/i18n';
import type { Except } from './types';

import { I18n as I18nBase } from '@meli/i18n';

import { I18n as I18nComponent, type I18nProps } from './components/I18n';

type I18nJsxCreatorData = {
  singularText: string;
  pluralText?: string;
  quantity?: number;
  context?: string;
  props: Except<I18nProps, 'text'>;
};

export type I18nJsxSettings = Except<I18nProps, 'text'>;

export type I18nJsxPluralSettings = I18nJsxSettings & {
  /**
   * Number to determine if singular or plural wording should be used.
   *
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsxngettext | Documentation}
   */
  quantity: number;
};

export type { I18nOptions, Locale, Translations } from '@meli/i18n';
export type { NordicI18nConfig } from './types';

export class I18n extends I18nBase {
  jsx = {
    /**
     * Given a text and settings, returns a translated JSX element.
     *
     * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsxgettext | Documentation}
     */
    gettext: (text: string, settings: I18nJsxSettings) =>
      this.#createJsxComponent({
        singularText: text,
        props: settings,
      }),

    /**
     * Given a text in singular, a text in plural form and settings with a quantity, returns a translated JSX element.
     *
     * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsxngettext | Documentation}
     */
    ngettext: (
      singularText: string,
      pluralText: string,
      settings: I18nJsxPluralSettings,
    ) =>
      this.#createJsxComponent({
        singularText,
        pluralText,
        quantity: settings.quantity,
        props: settings,
      }),

    /**
     * Given a text and a context, returns a translated JSX element.
     *
     * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsxpgettext | Documentation}
     */
    pgettext: (context: string, text: string, settings: I18nJsxSettings) =>
      this.#createJsxComponent({
        singularText: text,
        context,
        props: settings,
      }),

    /**
     * Given a text in singular and plural form, settings with a quantity and context, returns a translated JSX element.
     *
     * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsxnpgettext | Documentation}
     */
    npgettext: (
      context: string,
      singularText: string,
      pluralText: string,
      settings: I18nJsxPluralSettings,
    ) =>
      this.#createJsxComponent({
        singularText,
        pluralText,
        quantity: settings.quantity,
        context,
        props: settings,
      }),
  };

  toJSON(): I18nOptions {
    return {
      locale: this.locale,
      translations: this.translations,
    };
  }

  #createJsxComponent(data: I18nJsxCreatorData) {
    const { singularText, pluralText, quantity = 1, context, props } = data;
    const text =
      quantity === 1
        ? this.getTranslation(singularText, context)
        : this.getPluralTranslation(
            singularText,
            pluralText!,
            quantity,
            context,
          );

    return <I18nComponent {...props} text={text} />;
  }
}
