import { getWebviewInfo } from './getters';

/**
 * Returns whether the current context is a webview.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-context#iswebview | Documentation}
 *
 * @example
 *
 * import { isWebview } from 'nordic/context';
 *
 * const SomeComponent = () => (
 *   <h1>
 *     Is Webview: {isWebview() ? 'Yes' : 'No'}
 *   </h1>
 * );
 */
export const isWebview = () => !!getWebviewInfo();
