import ExecutionEnvironment from 'exenv';

// eslint-disable-next-line security/detect-unsafe-regex
const NATIVE_APP = /^(MercadoLibre|MercadoPago)-(iOS|Android)(?:\/|%2F)((?:\d+\.){2}\d+)/;

const getNativeApp = () => {
  if (!ExecutionEnvironment.canUseDOM) return;

  const userAgent = window?.navigator?.userAgent;
  const nativeAppArray = NATIVE_APP.exec(userAgent);

  if (!Array.isArray(nativeAppArray)) return;

  return {
    name: nativeAppArray[1],
    os: nativeAppArray[2],
    version: nativeAppArray[3],
  };
};

export default getNativeApp;
