import type { MergeExclusive } from '../types';

import { createElement } from 'react';

import { I18nWithValues, type I18nWithValuesProps } from './I18nWithValues';
import { I18nWithTags, type I18nWithTagsProps } from './I18nWithTags';
import {
  I18nWithComponents,
  type I18nWithComponentsProps,
} from './I18nWithComponents';
import { NordicI18nError } from '../error';

export type I18nProps = MergeExclusive<
  MergeExclusive<I18nWithTagsProps, I18nWithComponentsProps>,
  I18nWithValuesProps
>;

export const I18n = (props: I18nProps) => {
  const hasValues = 'values' in props;
  const hasTags = 'tags' in props;
  const hasComponents = 'components' in props;
  const hasReplacements = 'replacements' in props;

  if (__DEV__) {
    // Check for invalid combination: values with replacements
    if (hasValues && hasReplacements) {
      throw new NordicI18nError(
        '"values" and "replacements" properties cannot be used together. Use "values" for all replacements. See the docs regarding the use of i18n.jsx properties: ' +
          'https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsx',
      );
    }

    // Check that only one main prop type is used
    const propsCount = [hasValues, hasTags, hasComponents].filter(
      Boolean,
    ).length;

    if (propsCount > 1) {
      throw new NordicI18nError(
        '"tags", "components", and "values" properties cannot be used together. See the docs regarding the use of i18n.jsx properties: ' +
          'https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsx',
      );
    }

    if (propsCount === 0) {
      throw new NordicI18nError(
        'I18n JSX component requires the "values" prop. Refer to the docs regarding the use of i18n.jsx properties: ' +
          'https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#i18njsx',
      );
    }
  }

  // TypeScript discriminated union with type assertions after runtime validation
  if (hasValues) {
    return createElement(I18nWithValues, props as I18nWithValuesProps);
  }

  if (hasTags) {
    return createElement(I18nWithTags, props as I18nWithTagsProps);
  }

  return createElement(I18nWithComponents, props);
};
