import type { FunctionComponent, ReactElement } from 'react';
import type { I18nBaseProps, PrimitiveType } from './common';

import { createElement, Fragment, isValidElement } from 'react';

// User-facing interface with simplified function signature for better TypeScript inference
type I18nValues = Record<
  string,
  | PrimitiveType
  | ReactElement
  | (() => ReactElement)
  | ((chunks: string) => ReactElement)
>;

// Named placeholder regex patterns for react-intl style values. E.g. {name}
const NAMED_REPLACEMENT_REGEX = /\{([a-zA-Z_]\w*)\}/g;
// XML-like tag regex patterns for react-intl style rich text (only paired tags). E.g. <tag>content</tag>
const XML_TAG_REGEX = /<([a-zA-Z_]\w*)>(.*?)<\/\1>/g;

/**
 * Interpolate text with named placeholders, handling both primitive values and React elements
 */
const interpolateSimpleValues = (
  text: string,
  values: I18nValues,
): Array<ReactElement | string> => {
  const parts: Array<ReactElement | string> = [];
  const matches = text.matchAll(NAMED_REPLACEMENT_REGEX);

  let lastIndex = 0;

  for (const match of matches) {
    const [matchedText, key] = match as unknown as [string, string];

    // Add text before the match
    if (match.index > lastIndex) {
      parts.push(text.substring(lastIndex, match.index));
    }

    const value = values[key];

    if (typeof value === 'function') {
      // Skip functions in simple text processing
      parts.push(matchedText);
    } else if (isValidElement(value)) {
      // Handle React elements
      parts.push(<Fragment key={`${key}_${match.index}`}>{value}</Fragment>);
    } else if (value) {
      // Handle primitive values
      parts.push(`${value}`);
    } else {
      // Keep original text if no value found
      parts.push(matchedText);
    }

    lastIndex = match.index + matchedText.length;
  }

  // Add remaining text
  if (lastIndex < text.length) {
    parts.push(text.substring(lastIndex));
  }

  return parts;
};

/**
 * Recursively processes text with both {key} placeholders and <tag>content</tag> XML tags
 */
const processTextRecursively = (
  text: string,
  values: I18nValues,
): Array<ReactElement | string> => {
  const parts: Array<ReactElement | string> = [];
  const xmlMatches = text.matchAll(XML_TAG_REGEX);

  let textIndex = 0;

  for (const match of xmlMatches) {
    const [matchedText, tagName, content] = match as unknown as [
      string,
      string,
      string,
    ];

    // Handle {key} placeholders before XML-like placeholders
    const beforeText = text.substring(textIndex, match.index);

    if (beforeText) {
      parts.push(...interpolateSimpleValues(beforeText, values));
    }

    textIndex = match.index + matchedText.length;

    // Handle XML-like tags with content: <tag>content</tag>
    const value = values[tagName];

    if (typeof value === 'function') {
      // Recursively process the content inside the XML tag for both {key} placeholders AND nested XML tags
      const processedContent = content
        ? processTextRecursively(content, values)
        : [];
      const contentToPass =
        processedContent.length === 1 && typeof processedContent[0] === 'string'
          ? processedContent[0]
          : processedContent;

      // Call function with appropriate signature based on content type
      const result = (
        value as (chunks: Array<ReactElement | string> | string) => ReactElement
      )(contentToPass);

      parts.push(
        <Fragment key={`${tagName}_${content}_${match.index}`}>
          {result}
        </Fragment>,
      );
    } else {
      // If not a function, fall back to original text
      parts.push(matchedText);
    }
  }

  // Handle remaining {key} placeholders
  const trailingText = text.substring(textIndex);

  if (trailingText) {
    parts.push(...interpolateSimpleValues(trailingText, values));
  }

  return parts;
};

export type I18nWithValuesProps = I18nBaseProps & {
  /**
   * Replace placeholders with given values or React elements.
   *
   * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/nordic-i18n#settingsvalues | Documentation}
   * @example
   * i18n.jsx.gettext('Hello {name}! Click this <link>link</link>.', {
   *   values: {
   *     name: 'John',
   *     link: (chunks) => <a href="https://www.google.com">{chunks}</a>
   *   }
   * })
   * // Hello John! Click this <a href="https://www.google.com">link</a>.
   *
   * @example
   * i18n.jsx.ngettext(
   *   'Hello {name}! You have {count} message {icon}.',
   *   'Hello {name}! You have {count} messages {icon}.',
   *   {
   *     quantity: 10,
   *     values: { name: 'John', count: 10, icon: <span>✉️</span> }
   * })
   * // Hello John! You have 10 messages <span>✉️</span>.
   */
  values: I18nValues;
};

export const I18nWithValues: FunctionComponent<I18nWithValuesProps> = (
  props,
) => {
  const { wrapper, text, values, className } = props;

  // Use recursive processing to handle nested XML tags and {key} placeholders
  const children = processTextRecursively(text, values);

  if (wrapper) {
    return createElement(wrapper, { className }, children);
  }

  return children;
};
