import { toCssVars } from '../../utils/cssVarsUtils';
import { camelCaseToKebabCase, diffDeep, toCssValue } from '../../utils/utils';
import {
  separateComponentStylesFromComponentEntries,
  separateCssStylesFromCustomVars,
} from './ThemeBuilderUtils';
import { createThemeVarsMaps, createThemeVarsNames } from './ThemeVarsBuilder';
import mlTheme from '../../../meli-themes/ml.json';
import { componentVariantPrefix } from '../../constants';

/** @typedef {import('../../..').ThemeHash} ThemeHash */
/** @typedef {import('../../..').AndesProviderTheme} Theme */

/**
 * @param {Record<string, any>} styleOverrides
 *
 * @returns {string}
 */
const stylesObjectToCssStyles = (styleOverrides) =>
  Object.entries(styleOverrides)
    .map(([key, value]) => {
      const sanitizedKey = camelCaseToKebabCase(key);
      if (typeof value === 'object') {
        return `${sanitizedKey} {
          ${stylesObjectToCssStyles(value)}
        }`;
      }
      return toCssValue(sanitizedKey, value);
    })
    .join(' ');

/** @param {Record<string, any>} object */
const getObjectStyles = (object) => {
  if (typeof object !== 'object') {
    return '';
  }

  return stylesObjectToCssStyles(object);
};

/**
 * @param {string} component
 * @param {Record<string, any>} varsObject
 * @param {(componentStyles: Record<string, any>) => string} varMapper
 */
const getComponentVariables = (component, varsObject, varMapper) =>
  varMapper({ [component]: varsObject });

/**
 * @param {Theme["components"]} components
 * @param {import('../../..').GetComponentsStyles} componentClasses
 * @param {ThemeHash} themeHash
 * @param {string} prefix
 * @param {(componentStyles: Record<string, any>) => string} varMapper
 */
const buildComponentsStyles = (
  components,
  componentClasses,
  themeHash,
  prefix,
  varMapper,
) => {
  if (typeof components !== 'object') {
    return '';
  }

  return Object.entries(components)
    .filter(([component]) => componentClasses.has(component))
    .map(([component, componentEntriesObj]) => {
      const { componentStyles, componentOverrides } = separateComponentStylesFromComponentEntries(componentEntriesObj);

      const componentVariants = componentClasses.get(component)?.variants || [];

      const {
        keysInTargetAndSource: whitelistedComponentStyles,
        keysOnlyInTarget: customStyles,
      } = diffDeep(
        componentStyles,
        mlTheme.components[
          /** @type {keyof typeof mlTheme.components} */ (component)
        ] || {},
      );

      const { cssStyles, otherStyles } = separateCssStylesFromCustomVars(customStyles);

      const computedStyle = `
              ${getComponentVariables(component, whitelistedComponentStyles, varMapper)}
              ${getComponentVariables(component, otherStyles, varMapper)}
              ${getObjectStyles(cssStyles)}
              ${getObjectStyles(componentOverrides?.styleOverrides)}
              ${componentVariants.map((variant) => `&.${componentVariantPrefix}${variant.id} {${getObjectStyles(variant.styles)}}`).join(' ')}
      `.trim();

      if (computedStyle.length === 0) {
        return '';
      }

      const className = (componentClasses.get(component)?.className || '')
        .split(' ')
        .join('.');
      const [hashKey, hashValue] = Object.entries(themeHash)[0];
      const hashSelector = `${hashKey}=${hashValue}`;

      const cssSelectors = `
      .${className}[class^=${prefix}],
      .${className}[class^=${prefix}][${hashSelector}]
      `;

      return `${cssSelectors} {${computedStyle}}`;
    })
    .join(' ');
};

/**
 * @param {Theme} theme
 * @param {string} prefix
 * @param {ThemeHash} themeHash
 */
export const createCssVarsThemeStyles = (theme, prefix, themeHash) => {
  const { components = {} } = theme;
  const { coreVars, semanticLightVars, componentVarsMapper } = createThemeVarsMaps(theme, prefix);
  const themeVariables = createThemeVarsNames(theme, prefix);

  const coreAndSemanticVars = { ...coreVars, ...semanticLightVars };

  // const getDarkMode = () =>
  //   (Object.keys(semanticDarkVars).length > 0
  //     ? `@media(prefers-color-scheme: dark){${toCSSVars(semanticDarkVars, coreVars)}}`
  //     : '');

  const getCoreStyles = () => `
  ${toCssVars(coreVars)}
  ${toCssVars(semanticLightVars, coreVars)}`;

  /** @param {import('../../..').GetComponentsStyles} styledComponents */
  const getComponentsStyles = (styledComponents) =>
    buildComponentsStyles(
      components,
      styledComponents,
      themeHash,
      prefix,
      (componentStyles) =>
        toCssVars(componentVarsMapper(componentStyles), coreAndSemanticVars),
    );

  return { getCoreStyles, getComponentsStyles, themeVariables };
};
