import React, { Children } from 'react';
import PropTypes from 'prop-types';
import AndesContext from './AndesContext';
import getDevice from './utils/getDevice';

/** @type {typeof import('..').AndesProvider} */
const AndesProvider = ({ children, locale, device, csrfToken }) => {
  const localI18n = { translations: {}, locale };

  const value = {
    locale,
    i18n: localI18n,
    device: getDevice(device),
    csrfToken,
  };

  return (
    <AndesContext.Provider value={value}>
      {Children.only(children)}
    </AndesContext.Provider>
  );
};

AndesProvider.propTypes = {
  children: PropTypes.element.isRequired,
  // https://furydocs.io/m10e-service/latest/guide/#/wiki/terms?id=locales
  locale: PropTypes.oneOf(/** @type {const} */ ([
    'es-AR',
    'pt-BR',
    'es-PE',
    'es-BO',
    'es-CL',
    'es-CO',
    'es-CR',
    'es-DO',
    'es-EC',
    'es-GT',
    'es-HN',
    'es-NI',
    'es-PA',
    'es-PR',
    'es-PY',
    'es-SV',
    'es-UY',
    'es-VE',
    'es-MX',
    'en',
    'en-US',
    'zh-CN',
  ])).isRequired,
  // https://github.com/melisource/fury_frontend-device-detection#reqdevice
  device: PropTypes.shape({
    type: PropTypes.string,
    webView: PropTypes.bool,
    mobile: PropTypes.bool,
    osName: PropTypes.string,
    nativeApp: PropTypes.shape({ name: PropTypes.string, os: PropTypes.string, version: PropTypes.string }),
  }),
  csrfToken: PropTypes.string,
};

AndesProvider.displayName = 'AndesProvider';

export default AndesProvider;
