/** @returns {[
 * ReadonlyMap<string, import("../..").RegisterComponentsClassesObject>,
 * (component: string, componentClass: string, variant: Array<import("../..").CustomVariant>) => void]} */
export const useComponentRegister = () => {
  const themedComponents = /** @type {Map<string, import("../..").RegisterComponentsClassesObject>} */ (
    new Map()
  );

  /**
   * @param {string} component
   * @param {string} componentClass
   */
  const registerComponentClassName = (component, componentClass) => {
    if (!themedComponents.has(component)) {
      themedComponents.set(component, {
        className: componentClass,
        variants: [],
      });
    }
  };

  /**
   * @param {string} component
   * @param {Array<import("../..").CustomVariant>} variants
   */
  const registerComponentVariant = (component, variants) => {
    if (themedComponents.has(component)) {
      const oldValue = themedComponents.get(component);

      if (oldValue) {
        const existingVariantIds = new Set(
          oldValue.variants.map((variant) => variant.id),
        );
        const filteredVariants = variants.filter(
          (variant) => !existingVariantIds.has(variant.id),
        );
        const updatedVariants = [...oldValue.variants, ...filteredVariants];

        const newValue = {
          className: oldValue.className,
          variants: updatedVariants,
        };

        themedComponents.set(component, newValue);
      }
    }
  };

  /**
   * @param {string} component
   * @param {string} componentClass
   * @param {Array<import("../..").CustomVariant>} variants
   */
  const registerComponent = (component, componentClass, variants) => {
    registerComponentClassName(component, componentClass);
    registerComponentVariant(component, variants);
  };

  return [themedComponents, registerComponent];
};
