import type { NordicRenderingContext } from '../common/types';

import { throwContextNotInitializedError } from '../common/error';

export function getContext(): NordicRenderingContext {
  const context = window._n.ctx.r;

  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- Can be undefined in case the render has not been executed into the rendering context
  if (__DEV__ && !context) {
    throwContextNotInitializedError();
  }

  return context;
}
