// TODO: Remove this file when andes migrates to core getters
import {
  type NordicDeviceType,
  type NordicPlatformType,
  getDeviceType,
  getPlatformType,
  getWebviewInfo,
} from '@nordic/core-context';

export type NordicRenderingContextDeviceInfo = {
  type: NordicDeviceType;
  context: NordicPlatformType;
  webView: boolean;
};

export function getDeviceInfo(): NordicRenderingContextDeviceInfo {
  return {
    type: getDeviceType(),
    context: getPlatformType(),
    webView: !!getWebviewInfo(),
  };
}
