import { useContext } from 'react';
import { createTheme } from '../components/ThemeBuilder/ThemeBuilder';
import { mergeDeep } from '../utils/utils';
import { ThemeContext } from '../components/ThemeContext';
import mlTheme from '../../meli-themes/ml.json';
import mpTheme from '../../meli-themes/mp.json';

/** @typedef {import('../../').AndesProviderTheme} Theme */
/** @typedef {import('../../').AndesBaseTheme} AndesBaseTheme */

/**
 * @param {Theme} childTheme
 * @param {Theme} parentTheme
 */
const mergeChildAndParentThemes = (childTheme, parentTheme) => {
  const newTheme = /** @type {Theme} */ ({});

  Object.entries(childTheme).forEach(([key, value]) => {
    if (parentTheme[key] !== undefined) {
      newTheme[key] = mergeDeep(
        /** @type {Record<string, any>}* */ (parentTheme[key]),
        /** @type {Record<string, any>}* */ (value),
        { allowOnlySourceKeys: true },
      );
    }
  });

  return newTheme;
};

/**
 * @param {Theme} theme
 * @param {AndesBaseTheme} defaultThemeObject
 * @param {boolean} [override]
 *
 * @returns {Theme}
 */
const mergeThemes = (theme, defaultThemeObject, override) => {
  const { theme: parentTheme } = useContext(ThemeContext);

  if (override || !parentTheme) {
    return /** @type {Theme} */ (mergeDeep(defaultThemeObject, theme));
  }

  return mergeChildAndParentThemes(theme, parentTheme);
};

/** @type {typeof import('../..').useCreateTheme} */
export const useCreateTheme = (theme, defaultTheme, id, override) => {
  /** @type {AndesBaseTheme} */
  const defaultThemeObject = defaultTheme === 'MP' ? mpTheme : mlTheme;
  const mergedTheme = mergeThemes(theme, defaultThemeObject, override);

  return {
    theme: mergedTheme,
    ...createTheme(mergedTheme, id),
  };
};
