import { isAndesCssVar } from '../../utils/cssVarsUtils';

export const separateComponentStylesFromComponentEntries = (
  /** @type {Record<string, any>} */ componentEntriesObj = {},
) => {
  const {
    styleOverrides,
    variants: componentVariants = [],
    ...componentStyles
  } = componentEntriesObj;
  const componentOverrides = typeof styleOverrides === 'object' ? { styleOverrides } : {};

  return { componentStyles, componentOverrides, componentVariants };
};

/** @param {Record<string, any>} customStyles */
export const separateCssStylesFromCustomVars = (customStyles) => {
  const cssStyles = Object.fromEntries(
    Object.entries(customStyles).filter(
      ([key, value]) => typeof value !== 'object' && !isAndesCssVar(key),
    ),
  );

  const otherStyles = Object.fromEntries(
    Object.entries(customStyles).filter(
      ([, value]) => typeof value === 'object',
    ),
  );

  return { cssStyles, otherStyles };
};
