import { toVarsMap, toVarNames } from '../../utils/cssVarsUtils';

/** @typedef {import('../../..').AndesProviderTheme} Theme */

/**
 * @param {Theme["colorSchemes"]} colorSchemes
 * @param {(colorScheme: Record<string, any>) => Record<string, unknown>} varMapper
 *
 * @returns {{ semanticLightVars: Record<string, unknown>, semanticDarkVars: Record<string, unknown> }}
 */
const getColorSchemeVars = (colorSchemes, varMapper) => {
  let semanticLightVars = /** @type {Record<string, unknown>} */ ({});
  let semanticDarkVars = /** @type {Record<string, unknown>} */ ({});

  if (typeof colorSchemes === 'object') {
    if (typeof colorSchemes.light === 'object') {
      semanticLightVars = varMapper(colorSchemes.light);
    }

    // @ts-expect-error dark is not a property of colorSchemes until now
    if (typeof colorSchemes.dark === 'object') {
      // @ts-expect-error dark is not a property of colorSchemes until now
      semanticDarkVars = varMapper(colorSchemes.dark);
    }
  }

  return { semanticLightVars, semanticDarkVars };
};

/**
 * @param {Theme} theme
 * @param {string} prefix
 * @param {(obj: Record<string, unknown>, prefix: string) => Record<string, unknown>} varMapper
 */
const mapCoreAndSemanticVars = (theme, prefix, varMapper) => {
  const { core = {}, colorSchemes = {} } = theme;

  // core tier variables
  const coreVars = varMapper(core, prefix);

  // semantic tier variables
  const { semanticLightVars } = getColorSchemeVars(
    colorSchemes,
    (colorScheme) => varMapper(colorScheme, prefix),
  );

  return { coreVars, semanticLightVars };
};


/**
 * @param {Theme} theme
 * @param {string} prefix

 */
export const createThemeVarsMaps = (theme, prefix) => {
  const { coreVars, semanticLightVars } = mapCoreAndSemanticVars(theme, prefix, toVarsMap);

  // component tier variables mapper

  const componentVarsMapper = (
    /** @type {Record<string, any>} */ componentStyles,
  ) => toVarsMap(componentStyles, prefix);

  return (/** @type {{
    coreVars: Record<string, string>,
    semanticLightVars: Record<string, string>,
    componentVarsMapper: (componentStyles: Record<string, any>) => Record<string, string>
    }} */
    ({
      coreVars,
      semanticLightVars,
      componentVarsMapper,
    }));
};

/**
 * @param {Theme} theme
 * @param {string} prefix
 */
export const createThemeVarsNames = (theme, prefix) => {
  const { coreVars, semanticLightVars } = mapCoreAndSemanticVars(theme, prefix, toVarNames);

  return { core: coreVars, semantic: semanticLightVars };
};
