import isMobile from '@andes/common/build/utils/isMobile';
import getNativeApp from '@andes/common/build/utils/getNativeApp';
import getOsName from '@andes/common/build/utils/getOsName';

/** @param {import('../..').Device} [device] */
const getDevice = (device) => {
  if (typeof device !== 'undefined') return device;

  const basicDeviceData = {
    mobile: isMobile(),
    webView: typeof MobileWebKit !== 'undefined',
    nativeApp: getNativeApp(),
    osName: getOsName(),
  };

  return basicDeviceData;
};

export default getDevice;
