import { OwnerStackError } from '@nordic/utils/error';

export class NordicI18nError extends OwnerStackError {
  name = 'NordicI18nError';
}

export function throwI18nNotInitializedError(): never {
  throw new NordicI18nError(
    'I18n value is not initialized. Check that the I18n middleware is enabled.',
  );
}
